#ifdef ENABLE_DP
#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#endif

#ifdef ENABLE_HP
#pragma OPENCL EXTENSION cl_khr_fp16 : enable
#endif

#define CAT2(a, b) a##b
#define CAT(a, b) CAT2(a, b)

inline short conv_int_short(const int i) { return (short)i; }
inline int conv_int_int(const int i) { return i; }
inline float conv_int_float(const int i) { return (float)i; }

#ifdef ENABLE_DP
inline double conv_int_double(const int i) { return (double)i; }
#endif

#ifdef ENABLE_HP
inline half2 conv_int_half2(const int i) { return (half2)((half)i); }
#endif

inline short mad_short(const short a, const short b, const short c) {
  return (short)((uint)(ushort)a * (uint)(ushort)b + (uint)(ushort)c);
}

inline int mad_int(const int a, const int b, const int c) {
  return as_int((uint)a * (uint)b + (uint)c);
}

inline float mad_float(const float a, const float b, const float c) {
  return a * b + c;
}

#ifdef ENABLE_DP
inline double mad_double(const double a, const double b, const double c) {
  return a * b + c;
}
#endif

#ifdef ENABLE_HP
inline half2 mad_half2(const half2 a, const half2 b, const half2 c) {
  return a * b + c;
}
#endif

inline int equal_short(const short a, const short b) { return a == b; }
inline int equal_int(const int a, const int b) { return a == b; }
inline int equal_float(const float a, const float b) { return a == b; }

#ifdef ENABLE_DP
inline int equal_double(const double a, const double b) { return a == b; }
#endif

#ifdef ENABLE_HP
inline int equal_half2(const half2 a, const half2 b) { return all(a == b); }
#endif

#define CONV_INT(i) CAT(conv_int_, class_T)(i)
#define MAD(a, b, c) CAT(mad_, class_T)((a), (b), (c))
#define EQUAL(a, b) CAT(equal_, class_T)((a), (b))

__kernel void benchmark_func(class_T seed, __global class_T* g_data) {
  const size_t local_id = get_local_id(0);
  const size_t group_id = get_group_id(0);
  const size_t global_id = get_global_id(0);
  const size_t local_size = get_local_size(0);

#ifdef BLOCK_STRIDED
  const size_t stride = local_size;
  const size_t idx = group_id * local_size * (size_t)ELEMENTS_PER_THREAD + local_id;
  const size_t big_stride =
      get_num_groups(0) * local_size * (size_t)ELEMENTS_PER_THREAD;
#else
  const size_t stride = get_global_size(0);
  const size_t idx = global_id;
  const size_t big_stride = get_global_size(0) * (size_t)ELEMENTS_PER_THREAD;
#endif

  class_T tmps[ELEMENTS_PER_THREAD];

  for (int k = 0; k < FUSION_DEGREE; k++) {
    for (int j = 0; j < ELEMENTS_PER_THREAD; j++) {
      tmps[j] = g_data[idx + (size_t)j * stride + (size_t)k * big_stride];

      for (int i = 0; i < COMPUTE_ITERATIONS; i++) {
        tmps[j] = MAD(tmps[j], tmps[j], seed);
      }
    }

    class_T sum = CONV_INT(0);
    for (int j = 0; j + 1 < ELEMENTS_PER_THREAD; j += 2) {
      sum = MAD(tmps[j], tmps[j + 1], sum);
    }

    if (EQUAL(sum, CONV_INT(-1))) {
      g_data[idx + (size_t)k * big_stride] = sum;
    }
  }
}
